import os
import sys
import json
import base64
import requests
import msal

def load_connector_json(path="/run/connector.json"):
    try:
        with open(path, "r", encoding="utf-8") as f:
            return json.load(f)
    except Exception as e:
        print(json.dumps({"ok": False, "error": f"Failed to read connector.json: {e}"}))
        sys.exit(1)

def get_auth(cfg):
    auth = cfg.get("auth", {})
    tenant_id = os.getenv("AUTH_TENANTID") or auth.get("tenantId") or auth.get("tenant_id")
    client_id = os.getenv("AUTH_CLIENTID") or auth.get("clientId") or auth.get("client_id")
    client_secret = os.getenv("AUTH_CLIENTSECRET") or auth.get("clientSecret") or auth.get("client_secret")
    if not tenant_id or not client_id or not client_secret:
        print(json.dumps({"ok": False, "error": "Missing Azure AD credentials: tenantId, clientId, clientSecret"}))
        sys.exit(1)
    return tenant_id, client_id, client_secret

def normalize_emails(value):
    if value is None:
        return []
    if isinstance(value, str):
        return [e.strip() for e in value.split(",") if e.strip()]
    if isinstance(value, list):
        return [str(e).strip() for e in value if str(e).strip()]
    return []

def build_message(conf):
    from_address = conf.get("fromAddress")
    recipients = normalize_emails(conf.get("recipients"))
    cc = normalize_emails(conf.get("cc"))
    bcc = normalize_emails(conf.get("bcc"))
    reply_to = normalize_emails(conf.get("replyTo"))
    subject = conf.get("subject")
    body = conf.get("body")
    content_type = str(conf.get("contentType") or "text").strip().lower()
    save_to_sent = bool(conf.get("saveToSentItems", True))
    attachments = conf.get("attachments") or []

    if not from_address:
        return None, None, "configuration.fromAddress is required"
    if not recipients:
        return None, None, "configuration.recipients must contain at least one email"
    if not subject:
        return None, None, "configuration.subject is required"
    if body is None:
        return None, None, "configuration.body is required"

    ct = "HTML" if content_type == "html" else "Text"

    msg = {
        "subject": subject,
        "body": {"contentType": ct, "content": body},
        "toRecipients": [{"emailAddress": {"address": a}} for a in recipients]
    }
    if cc:
        msg["ccRecipients"] = [{"emailAddress": {"address": a}} for a in cc]
    if bcc:
        msg["bccRecipients"] = [{"emailAddress": {"address": a}} for a in bcc]
    if reply_to:
        msg["replyTo"] = [{"emailAddress": {"address": a}} for a in reply_to]

    atts = []
    for att in attachments:
        try:
            name = att.get("name")
            content_type_att = att.get("contentType") or "application/octet-stream"
            content_bytes = att.get("contentBytes")
            if not name or not content_bytes:
                continue
            # Ensure contentBytes is base64 string
            # Attempt a round-trip decode/encode to validate
            try:
                base64.b64decode(content_bytes)
            except Exception:
                # If not base64, try to encode provided text
                content_bytes = base64.b64encode(str(content_bytes).encode("utf-8")).decode("ascii")
            atts.append({
                "@odata.type": "#microsoft.graph.fileAttachment",
                "name": name,
                "contentType": content_type_att,
                "contentBytes": content_bytes
            })
        except Exception:
            continue
    if atts:
        msg["attachments"] = atts

    payload = {"message": msg, "saveToSentItems": save_to_sent}
    return from_address, payload, None

def acquire_token(tenant_id, client_id, client_secret):
    authority = f"https://login.microsoftonline.com/{tenant_id}"
    app = msal.ConfidentialClientApplication(client_id=client_id, authority=authority, client_credential=client_secret)
    result = app.acquire_token_for_client(scopes=["https://graph.microsoft.com/.default"])
    if not result or "access_token" not in result:
        return None, result
    return result["access_token"], None

def send_mail(access_token, from_address, payload):
    url = f"https://graph.microsoft.com/v1.0/users/{from_address}/sendMail"
    headers = {"Authorization": f"Bearer {access_token}", "Content-Type": "application/json"}
    resp = requests.post(url, headers=headers, json=payload, timeout=30)
    ok = 202 == resp.status_code or 204 == resp.status_code
    return ok, resp.status_code, safe_resp_json(resp)

def safe_resp_json(resp):
    try:
        return resp.json()
    except Exception:
        return {"text": resp.text}

def main():
    cfg = load_connector_json()
    tenant_id, client_id, client_secret = get_auth(cfg)
    from_address, payload, err = build_message(cfg.get("configuration", {}))
    if err:
        print(json.dumps({"ok": False, "error": err}))
        sys.exit(1)
    token, token_err = acquire_token(tenant_id, client_id, client_secret)
    if not token:
        print(json.dumps({"ok": False, "error": "Failed to acquire token", "details": token_err}))
        sys.exit(1)
    ok, status, body = send_mail(token, from_address, payload)
    if ok:
        msg = payload.get("message", {})
        tos = [r.get("emailAddress", {}).get("address") for r in msg.get("toRecipients", [])]
        print(json.dumps({"ok": True, "status": status, "sentFrom": from_address, "to": tos}))
        sys.exit(0)
    else:
        print(json.dumps({"ok": False, "status": status, "error": body}))
        sys.exit(1)

if __name__ == "__main__":
    main()
